class Solution{public boolean isMatch(String s,String p){int m=s.length(),n=p.length();boolean[]dp=new boolean[n+1];dp[0]=true;for(int j=1;j<=n;j++)if(p.charAt(j-1)=='*')dp[j]=dp[j-1];for(int i=1;i<=m;i++){boolean prev=dp[0];dp[0]=false;for(int j=1;j<=n;j++){boolean t=dp[j];if(p.charAt(j-1)=='*')dp[j]=dp[j]||dp[j-1];else if(p.charAt(j-1)=='?'||s.charAt(i-1)==p.charAt(j-1))dp[j]=prev;else dp[j]=false;prev=t;}}return dp[n];}}